import json


class Payload(object):
    def __init__(self, data=None):
        self.data = data


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps(payload.__dict__).encode('utf-8')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get raw data from the request body
    data = request.get_data(as_text=True)

    if not data:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent execution of arbitrary Python objects (CWE-502)
        parsed_data = yaml.safe_load(data)

        # Ensure the result is a type that can be serialized to JSON
        if parsed_data is None:
            return jsonify({"result": None})

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except TypeError as e:
        return jsonify({"error": f"YAML content is not JSON-serializable: {str(e)}"}), 400
